// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, assignment, and management utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks/transfer', auth: true },
    ],
    functions: ['transferTask'],
    types: ['Task', 'Team', 'TransferError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'reads from: teams table',
    'emits event: task.transferred',
  ],

  invariants: [
    'A task must always be assigned to exactly one team',
    'Only admins can transfer tasks between teams',
    'Transfer must update the task and emit a transferred event',
  ],
});

// modules/tasks/lib/transfer.ts
import { Result, ok, err } from '/lib/result';
import { requireUser, getSession } from '/lib/auth';
import { query } from '/lib/db';
import { Task, Team, TransferError } from '/lib/types';

export async function transferTask(req: Request): Promise<Result<Task, TransferError>> {
  const user = await requireUser(req);
  if (!user.isAdmin) return err({ code: 'NOT_ADMIN', message: 'Only admins can transfer tasks' });

  const { taskId, targetTeamId } = parseBody<{ taskId: string; targetTeamId: string }>(req);

  const task = await query<Task>('SELECT * FROM tasks WHERE id = $1', [taskId]);
  if (!task) return err({ code: 'TASK_NOT_FOUND', message: 'Task not found' });

  const sourceTeam = await query<Team>('SELECT * FROM teams WHERE id = $1', [task.teamId]);
  if (!sourceTeam) return err({ code: 'SOURCE_TEAM_NOT_FOUND', message: 'Source team not found' });

  const targetTeam = await query<Team>('SELECT * FROM teams WHERE id = $1', [targetTeamId]);
  if (!targetTeam) return err({ code: 'TARGET_TEAM_NOT_FOUND', message: 'Target team not found' });

  if (sourceTeam.id !== task.teamId) return err({ code: 'INVALID_TASK_TEAM', message: 'Task is not assigned to the source team' });

  await query('UPDATE tasks SET team_id = $1 WHERE id = $2', [targetTeamId, taskId]);

  emitEvent('task.transferred', { taskId, fromTeamId: sourceTeam.id, toTeamId: targetTeam.id });

  return ok(task);
}

// modules/tasks/routes/transfer.ts
import { defineRoute } from 'aether';
import { transferTask } from '/modules/tasks/lib/transfer';

export default defineRoute({
  method: 'POST',
  path: '/tasks/transfer',
  auth: true,
  handler: async (req) => {
    const result = await transferTask(req);
    if (result.isErr()) return new Response(JSON.stringify(result.error), { status: 400 });
    return new Response(JSON.stringify(result.value), { status: 200 });
  },
});

// modules/tasks/lib/queries.ts
import { query } from '/lib/db';

export async function getTaskById(taskId: string): Promise<Task | null> {
  const result = await query<Task>('SELECT * FROM tasks WHERE id = $1', [taskId]);
  return result;
}

export async function getTeamById(teamId: string): Promise<Team | null> {
  const result = await query<Team>('SELECT * FROM teams WHERE id = $1', [teamId]);
  return result;
}

// modules/tasks/lib/types.ts
import { Result, ok, err } from '/lib/result';
import { User, Team } from '/lib/types';

export interface Task {
  id: string;
  title: string;
  description: string;
  teamId: string;
}

export interface TransferError {
  code: string;
  message: string;
}

// modules/tasks/lib/events.ts
import { emitEvent } from '/lib/events';

export function emitTaskTransferredEvent(taskId: string, fromTeamId: string, toTeamId: string): void {
  emitEvent('task.transferred', { taskId, fromTeamId, toTeamId });
}

